// https://www3.ntu.edu.sg/home/ehchua/programming/java/JavaNativeInterface.html

// Tests analysis of native code:
//
// (a) JNI calls. These can be handled by HeapDL and the included
// java.hprof (or equivalent HPROF data generated by `make
// capture_hprof`). With HPROF support, "obj" should point to a value.
//
// (b) Use of UnixFileSystem.list() which is native in OpenJDK and
// explicitly modelled by Doop. Local variable "list" should point to
// such a native object.

import java.io.*;
import java.lang.management.*;
import java.net.*;
import java.nio.file.*;

public class HelloJNI {
    static {
        // String ARCH = "x86";
        String ARCH = "x86-64";
        String libName = "libhello.so";
        URL url = HelloJNI.class.getResource("/lib/" + ARCH + "/" + libName);
        try {
            File tmpDir = Files.createTempDirectory("libhello").toFile();
            tmpDir.deleteOnExit();
            File libTmpFile = new File(tmpDir, libName);
            libTmpFile.deleteOnExit();
            try (InputStream in = url.openStream()) {
                Files.copy(in, libTmpFile.toPath());
                System.load(libTmpFile.getCanonicalPath());
            }
        } catch (IOException ex) {
            System.err.println("Could not load " + libName);
        }
    }
 
    // Declare a native method sayHello() that receives nothing and returns void
    private native void sayHello();
    private native Object newJNIObj();
    private native void callBack(Object obj);
    private native void customRegisteredMethod(Object obj);

    static Object sObj;
    private Object iObj;

    // Test Driver
    public static void main(String[] args) {
        HelloJNI hj = new HelloJNI();
        hj.sayHello();  // invoke the native method
        Object obj = hj.newJNIObj();
        System.out.println(obj.toString());

        sObj = hj.newJNIObj();
        System.out.println(sObj.toString());

        File f = new File(".");
        FileSystem ufs = FileSystems.getDefault();
        System.out.println("ufs.getClass() = " + ufs.getClass().getName());
        String[] list = f.list();
        System.out.println("== Contents of current dir ==");
        for (String entry : list) {
            System.out.println(entry);
        }

        hj.callBack(new Object());
        hj.customRegisteredMethod(new Object());

        System.out.println(hj.iObj.hashCode());

        if (isAot())
            System.out.println("Running under GraalVM/native-image, skipping heap dump.");
        else
            dumpHeap();
    }

    private static boolean isAot() {
        try {
            Class<?> c = Class.forName("org.graalvm.nativeimage.ImageInfo");
            java.lang.reflect.Method m = c.getMethod("inImageCode", new Class[] { });
            return (Boolean)(m.invoke(c));
        } catch (Exception ex) {
        }
        return false;
    }

    private static void dumpHeap() {
        // Java 9
        // long pid = ProcessHandle.current().pid();
        // Java 8
        String name = ManagementFactory.getRuntimeMXBean().getName();
        String pid = name.substring(0, name.indexOf("@"));
        try {
            long millis = System.currentTimeMillis();
            String file = (new java.io.File("heap-dump-"+millis+".hprof")).getCanonicalPath();
            String javaHome = System.getenv("JAVA_HOME");
            String cmd = javaHome + "/bin/jmap -dump:format=b,file=" + file + " " + pid;
            System.out.println("Running: " + cmd);
            Runtime.getRuntime().exec(cmd);
            short secs = 6;
            System.out.println("Waiting " + secs + " secs for heap dump to finish...");
            Thread.sleep(secs * 1000);
        } catch (Exception ex) {
            ex.printStackTrace();
        }
    }

    public int helloMethod(Object obj1, Object obj2) {
        System.out.println(obj1.hashCode());
        System.out.println(obj2.hashCode());
        iObj = new Object();
        System.out.println(iObj.hashCode());
        return 1;
    }

    public int helloMethod2(Object obj) {
        return helloMethod(obj, obj);
    }
}
